// Eager: parseData() called on EVERY render, result ignored after first
const [data, setData] = useState(parseData(rawInput));

// Lazy: parseData called ONCE on first render only
const [data, setData] = useState(() => parseData(rawInput));
// or equivalently, passing the function reference directly:
const [data, setData] = useState(parseData); // only valid if parseData takes no args

function ThemeSelector() {
  // Eager: reads localStorage on every render
  // const [theme, setTheme] = useState(localStorage.getItem('theme') ?? 'light');

  // Lazy: reads localStorage once, at mount
  const [theme, setTheme] = useState(
    () => localStorage.getItem('theme') ?? 'light'
  );

  function toggle() {
    const next = theme === 'light' ? 'dark' : 'light';
    setTheme(next);
    localStorage.setItem('theme', next);
  }

  return (
    <button onClick={toggle}>
      Switch to {theme === 'light' ? 'dark' : 'light'} mode
    </button>
  );
}

function DataGrid({ rawRows }) {
  // rawRows.map + filter could touch thousands of items
  const [rows, setRows] = useState(() =>
    rawRows
      .filter(r => r.active)
      .map(r => ({ ...r, selected: false }))
  );

  // rows is independent state after mount — rawRows changes don't reset it
  return <table>{/* render rows */}</table>;
}

function SearchPage() {
  const [filters, setFilters] = useState(() => {
    const params = new URLSearchParams(window.location.search);
    return {
      query: params.get('q') ?? '',
      category: params.get('cat') ?? 'all',
      page: Number(params.get('page') ?? '1'),
    };
  });

  // filters.query, filters.category, filters.page are live state
  // The URL is only read at mount
  return <SearchUI filters={filters} onFilter={setFilters} />;
}

