function Counter({ initialCount, step }) {
  // Props are available in the closure
  const [count, setCount] = useState(() => {
    // Could do validation, clamping, etc.
    return Math.max(0, initialCount); // clamp to non-negative
  });

  return (
    <button onClick={() => setCount(c => c + step)}>
      Count: {count}
    </button>
  );
}

