function Page() {
  // Lazy initializer — synchronous data available immediately
  const [prefs, setPrefs] = useState(() =>
    JSON.parse(localStorage.getItem('prefs') || '{}')
  );

  // useEffect — async data not available synchronously
  const [user, setUser] = useState(null);
  useEffect(() => {
    fetch('/api/me').then(r => r.json()).then(setUser);
  }, []);

  if (!user) return <p>Loading…</p>;
  return <Dashboard prefs={prefs} user={user} />;
}

function useLocalStorage(key, initialValue) {
  const [stored, setStored] = useState(() => {
    try {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setValue = value => {
    try {
      const next = value instanceof Function ? value(stored) : value;
      setStored(next);
      localStorage.setItem(key, JSON.stringify(next));
    } catch { /* ignore quota errors */ }
  };

  return [stored, setValue];
}

// Usage
function Settings() {
  const [theme, setTheme] = useLocalStorage('theme', 'light');
  return (
    <button onClick={() => setTheme(t => t === 'light' ? 'dark' : 'light')}>
      Theme: {theme}
    </button>
  );
}

function Parent({ userId }) {
  // When userId changes, the DataGrid is remounted and the
  // lazy initializer re-runs with the new rawRows
  return <DataGrid key={userId} rawRows={fetchCachedRows(userId)} />;
}

import { render, screen, act } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

const expensive = jest.fn(() => 42);

function Component() {
  const [value, setValue] = useState(expensive);
  return <button onClick={() => setValue(v => v + 1)}>{value}</button>;
}

test('initializer runs exactly once', async () => {
  const user = userEvent.setup();
  render(<Component />);

  expect(expensive).toHaveBeenCalledTimes(1);
  expect(screen.getByRole('button')).toHaveTextContent('42');

  await user.click(screen.getByRole('button'));
  // After state update, expensive should still have been called only once
  expect(expensive).toHaveBeenCalledTimes(1);
  expect(screen.getByRole('button')).toHaveTextContent('43');
});

