function buildLookup(rows) {
  return rows.reduce((acc, row) => { acc[row.id] = row; return acc; }, {});
}

const ROWS = Array.from({ length: 50_000 }, (_, i) => ({ id: i, name: `Item ${i}` }));

function EagerVersion() {
  // buildLookup runs on every render
  const [lookup] = useState(buildLookup(ROWS));
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

function LazyVersion() {
  // buildLookup runs once at mount
  const [lookup] = useState(() => buildLookup(ROWS));
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

function initState(storedKey) {
  try { return JSON.parse(localStorage.getItem(storedKey) || '[]'); }
  catch { return []; }
}

function reducer(state, action) {
  switch (action.type) {
    case 'add': return [...state, action.item];
    case 'remove': return state.filter(i => i.id !== action.id);
    default: return state;
  }
}

function TaskManager() {
  // initState('tasks') called once at mount
  const [tasks, dispatch] = useReducer(reducer, 'tasks', initState);
  return (
    <ul>
      {tasks.map(t => (
        <li key={t.id}>
          {t.text}
          <button onClick={() => dispatch({ type: 'remove', id: t.id })}>x</button>
        </li>
      ))}
    </ul>
  );
}

